/* CISSP :: content/quiz4.js — CISSP Domain 4 question bank (100 items). */
window.CISSP = window.CISSP || {}; CISSP.questions = CISSP.questions || [];
CISSP.questions.push(
{ id:"D4-001", domain:4, obj:"4.1", diff:"easy", q:"At which layer of the OSI model does a router make forwarding decisions using logical IP addresses?", options:["Layer 3 (Network)","Layer 2 (Data Link)","Layer 4 (Transport)","Layer 7 (Application)"], answer:0, explain:"<strong>Layer 3 (Network)</strong> is where logical addressing (IP) and routing occur, so a router that forwards on IP addresses operates at the Network layer.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Layer 2 (Data Link)</b>: Layer 2 uses MAC addresses and is where switches operate, not IP routing.</span><span class='qd'><b>Layer 4 (Transport)</b>: Layer 4 handles segmentation and port-based delivery (TCP/UDP), not IP forwarding.</span><span class='qd'><b>Layer 7 (Application)</b>: Layer 7 is where user-facing protocols live and has no role in packet forwarding.</span>" },
{ id:"D4-002", domain:4, obj:"4.1", diff:"easy", q:"A switch that forwards frames based on hardware addresses operates primarily at which OSI layer?", options:["Layer 1 (Physical)","Layer 2 (Data Link)","Layer 3 (Network)","Layer 5 (Session)"], answer:1, explain:"<strong>Layer 2 (Data Link)</strong> uses MAC (hardware) addresses to switch frames within a broadcast domain, which is the classic role of a switch.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Layer 1 (Physical)</b>: Layer 1 concerns bits, cabling, and signaling, not MAC-based forwarding.</span><span class='qd'><b>Layer 3 (Network)</b>: Layer 3 forwards on IP addresses (routing), which is a router function.</span><span class='qd'><b>Layer 5 (Session)</b>: Layer 5 manages dialog sessions and has nothing to do with frame switching.</span>" },
{ id:"D4-003", domain:4, obj:"4.1", diff:"easy", q:"Which transport-layer protocol provides reliable, connection-oriented delivery with sequencing and acknowledgments?", options:["UDP","ICMP","TCP","ARP"], answer:2, explain:"<strong>TCP</strong> is connection-oriented and reliable, using a three-way handshake, sequence numbers, and acknowledgments to guarantee ordered delivery.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>UDP</b>: UDP is connectionless and unreliable, with no sequencing or acknowledgments.</span><span class='qd'><b>ICMP</b>: ICMP is a Layer 3 control/diagnostic protocol (ping, unreachable), not a reliable transport.</span><span class='qd'><b>ARP</b>: ARP resolves IP to MAC at Layer 2 and provides no data delivery service.</span>" },
{ id:"D4-004", domain:4, obj:"4.1", diff:"medium", q:"A security engineer must protect web traffic in transit for a customer portal. Which protocol provides the BEST modern, standards-based encryption for that HTTP traffic?", options:["SSL 3.0","Telnet","FTP","TLS 1.2 or 1.3"], answer:3, explain:"<strong>TLS 1.2 or 1.3</strong> is the current standard for encrypting HTTP (HTTPS) traffic in transit, offering strong ciphers and forward secrecy.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>SSL 3.0</b>: SSL 3.0 is deprecated and vulnerable (e.g., POODLE) and must not be used.</span><span class='qd'><b>Telnet</b>: Telnet is a plaintext remote-terminal protocol, not for web traffic and not encrypted.</span><span class='qd'><b>FTP</b>: FTP transfers files in cleartext and does not encrypt web sessions.</span>" },
{ id:"D4-005", domain:4, obj:"4.1", diff:"easy", q:"Which port and protocol pairing is correct for standard HTTPS traffic?", options:["TCP 443","TCP 80","UDP 53","TCP 23"], answer:0, explain:"<strong>TCP 443</strong> is the well-known port for HTTPS (HTTP over TLS).<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>TCP 80</b>: TCP 80 is plaintext HTTP, not HTTPS.</span><span class='qd'><b>UDP 53</b>: UDP 53 is DNS query traffic, unrelated to secure web browsing.</span><span class='qd'><b>TCP 23</b>: TCP 23 is Telnet, an insecure remote-access protocol.</span>" },
{ id:"D4-006", domain:4, obj:"4.1", diff:"easy", q:"Which protocol and port pair is used for secure shell (SSH) remote administration?", options:["TCP 21","TCP 22","UDP 69","TCP 25"], answer:1, explain:"<strong>TCP 22</strong> is the standard port for SSH, which provides encrypted remote command-line access and secure file transfer.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>TCP 21</b>: TCP 21 is the FTP control channel, which is unencrypted.</span><span class='qd'><b>UDP 69</b>: UDP 69 is TFTP, a trivial, unauthenticated file transfer protocol.</span><span class='qd'><b>TCP 25</b>: TCP 25 is SMTP for mail relay, not remote shell.</span>" },
{ id:"D4-007", domain:4, obj:"4.1", diff:"medium", q:"An organization wants to encrypt DNS queries so resolver traffic cannot be read or tampered with on the wire. Which technology BEST meets that goal?", options:["DNSSEC","Split-horizon DNS","DNS over HTTPS (DoH)","Round-robin DNS"], answer:2, explain:"<strong>DNS over HTTPS (DoH)</strong> encrypts DNS queries inside HTTPS, providing confidentiality and integrity of the resolver traffic on the wire.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>DNSSEC</b>: DNSSEC authenticates records with signatures to prevent spoofing but does not encrypt the query traffic.</span><span class='qd'><b>Split-horizon DNS</b>: split-horizon serves different answers to internal vs. external clients and provides no encryption.</span><span class='qd'><b>Round-robin DNS</b>: round-robin distributes load across addresses and offers no confidentiality.</span>" },
{ id:"D4-008", domain:4, obj:"4.1", diff:"medium", q:"Which statement BEST describes the primary purpose of DNSSEC?", options:["It encrypts DNS query contents end to end","It hides internal hostnames from external users","It load-balances queries across multiple servers","It authenticates DNS responses with digital signatures to prevent spoofing"], answer:3, explain:"<strong>It authenticates DNS responses with digital signatures to prevent spoofing</strong> captures DNSSEC's role: it establishes a chain of trust so resolvers can verify records are authentic and unaltered.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It encrypts DNS query contents end to end</b>: DNSSEC provides integrity/authenticity, not confidentiality; DoH/DoT encrypt.</span><span class='qd'><b>It hides internal hostnames from external users</b>: that is split-horizon DNS, not DNSSEC.</span><span class='qd'><b>It load-balances queries across multiple servers</b>: that is a function of round-robin or GSLB, not DNSSEC.</span>" },
{ id:"D4-009", domain:4, obj:"4.1", diff:"medium", q:"A security architect is choosing an IPsec mode to protect traffic between two site gateways while hiding the original host IP addresses. Which choice is BEST?", options:["Tunnel mode with ESP","Transport mode with AH","Transport mode with ESP","AH only in tunnel mode"], answer:0, explain:"<strong>Tunnel mode with ESP</strong> encapsulates and encrypts the entire original IP packet, so a gateway-to-gateway VPN both protects payloads and conceals the internal host addresses.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Transport mode with AH</b>: transport mode leaves the original IP header exposed and AH provides no encryption.</span><span class='qd'><b>Transport mode with ESP</b>: transport mode protects the payload but does not hide the original host IP header the way tunnel mode does.</span><span class='qd'><b>AH only in tunnel mode</b>: AH provides authentication/integrity but no confidentiality, so host addresses are not concealed by encryption.</span>" },
{ id:"D4-010", domain:4, obj:"4.1", diff:"medium", q:"Within IPsec, which component provides confidentiality (encryption) of the packet payload?", options:["AH (Authentication Header)","ESP (Encapsulating Security Payload)","IKE Phase 1","SA lifetime"], answer:1, explain:"<strong>ESP (Encapsulating Security Payload)</strong> provides confidentiality through encryption, and can also provide integrity and authentication of the payload.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>AH (Authentication Header)</b>: AH offers integrity and origin authentication but no encryption.</span><span class='qd'><b>IKE Phase 1</b>: IKE negotiates keys and establishes the secure channel but is not the data-encryption service itself.</span><span class='qd'><b>SA lifetime</b>: an SA lifetime is a parameter controlling rekeying, not an encryption mechanism.</span>" },
{ id:"D4-011", domain:4, obj:"4.1", diff:"hard", q:"During IPsec setup, which phase of IKE is responsible for authenticating the peers and establishing a secure channel to protect subsequent negotiation?", options:["IKE Phase 2 (IPsec SA)","ESP transform negotiation","IKE Phase 1 (ISAKMP SA)","Dead Peer Detection"], answer:2, explain:"<strong>IKE Phase 1 (ISAKMP SA)</strong> authenticates the peers and builds the protected management channel used to negotiate the later IPsec SAs.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>IKE Phase 2 (IPsec SA)</b>: Phase 2 negotiates the actual data-protection SAs inside the channel Phase 1 already secured.</span><span class='qd'><b>ESP transform negotiation</b>: transform sets are negotiated as part of Phase 2, not the initial peer authentication.</span><span class='qd'><b>Dead Peer Detection</b>: DPD detects a failed peer during an existing session; it does not establish the channel.</span>" },
{ id:"D4-012", domain:4, obj:"4.1", diff:"medium", q:"An analyst wants to know which OSI layers the TCP/IP model's Internet layer maps to. Which mapping is correct?", options:["Application, Presentation, and Session","Transport only","Physical and Data Link","Network (Layer 3)"], answer:3, explain:"<strong>Network (Layer 3)</strong> is the OSI layer that corresponds to the TCP/IP Internet layer, which handles IP addressing and routing.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Application, Presentation, and Session</b>: those three OSI layers map to the TCP/IP Application layer, not the Internet layer.</span><span class='qd'><b>Transport only</b>: the OSI Transport layer maps to the TCP/IP Transport (Host-to-Host) layer, not the Internet layer.</span><span class='qd'><b>Physical and Data Link</b>: those map to the TCP/IP Link/Network Access layer, not the Internet layer.</span>" },
{ id:"D4-013", domain:4, obj:"4.1", diff:"easy", q:"Which OSI layer is responsible for translating data formats, such as character encoding and encryption/compression, between applications?", options:["Presentation (Layer 6)","Session (Layer 5)","Application (Layer 7)","Transport (Layer 4)"], answer:0, explain:"<strong>Presentation (Layer 6)</strong> handles data representation tasks such as encoding, encryption, and compression so applications can interoperate.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Session (Layer 5)</b>: the Session layer sets up, manages, and tears down dialogs, not format translation.</span><span class='qd'><b>Application (Layer 7)</b>: Layer 7 provides the interface to user applications, not encoding/translation.</span><span class='qd'><b>Transport (Layer 4)</b>: Layer 4 handles reliability and segmentation, not data representation.</span>" },
{ id:"D4-014", domain:4, obj:"4.1", diff:"medium", q:"A CISO reviews a converged network that carries voice, video, and data on the same IP infrastructure. Which control MOST directly ensures voice quality is protected from data congestion?", options:["A longer DHCP lease","Quality of Service (QoS) marking and queuing","Larger MTU on every link","Disabling spanning tree"], answer:1, explain:"<strong>Quality of Service (QoS) marking and queuing</strong> classifies and prioritizes latency-sensitive voice traffic so it is not degraded by bursts of data on a converged network.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A longer DHCP lease</b>: lease duration affects address assignment, not real-time traffic prioritization.</span><span class='qd'><b>Larger MTU on every link</b>: larger frames can actually increase serialization delay and do not prioritize voice.</span><span class='qd'><b>Disabling spanning tree</b>: disabling STP risks loops and broadcast storms, harming stability rather than voice quality.</span>" },
{ id:"D4-015", domain:4, obj:"4.1", diff:"hard", q:"In a software-defined network (SDN), which plane is responsible for making forwarding decisions and is logically centralized in a controller?", options:["Data plane","Management plane","Control plane","Application plane"], answer:2, explain:"<strong>Control plane</strong> in SDN is decoupled from the switches and centralized in a controller that computes forwarding logic and programs the data plane.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Data plane</b>: the data (forwarding) plane simply moves packets per rules pushed down by the controller.</span><span class='qd'><b>Management plane</b>: the management plane handles configuration and monitoring, not real-time forwarding decisions.</span><span class='qd'><b>Application plane</b>: the application plane hosts network apps that request services via the controller's northbound API.</span>" },
{ id:"D4-016", domain:4, obj:"4.1", diff:"hard", q:"A security architect notes that SDN centralizes control logic. From a risk perspective, what is the MOST significant new concern this design introduces?", options:["Slower cabling installation","Loss of the ability to use IP addressing","Inability to run any firewall","The controller becomes a high-value single point of compromise"], answer:3, explain:"<strong>The controller becomes a high-value single point of compromise</strong> because centralizing the control plane means an attacker who seizes the controller can reprogram the entire fabric, so it must be hardened and highly available.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Slower cabling installation</b>: SDN concerns control logic, not physical cabling speed.</span><span class='qd'><b>Loss of the ability to use IP addressing</b>: SDN still uses standard IP addressing on the data plane.</span><span class='qd'><b>Inability to run any firewall</b>: SDN can integrate virtual and physical firewalls; it does not preclude them.</span>" },
{ id:"D4-017", domain:4, obj:"4.1", diff:"medium", q:"An enterprise adopts SD-WAN to connect branch offices. Which benefit is MOST characteristic of SD-WAN over traditional MPLS-only WANs?", options:["It dynamically steers traffic across multiple transport links based on policy and link quality","It eliminates the need for any encryption","It removes the need for IP addresses at branches","It guarantees zero latency"], answer:0, explain:"<strong>It dynamically steers traffic across multiple transport links based on policy and link quality</strong> is SD-WAN's hallmark: application-aware, centrally managed path selection across broadband, LTE, and MPLS.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It eliminates the need for any encryption</b>: SD-WAN typically adds IPsec overlays; it does not remove the need for encryption.</span><span class='qd'><b>It removes the need for IP addresses at branches</b>: branches still use IP addressing.</span><span class='qd'><b>It guarantees zero latency</b>: no technology guarantees zero latency; SD-WAN optimizes, it does not eliminate, latency.</span>" },
{ id:"D4-018", domain:4, obj:"4.1", diff:"medium", q:"A wireless team must select the STRONGEST enterprise Wi-Fi security available today. Which option should they choose?", options:["WEP","WPA3-Enterprise","WPA2-Personal","Open with a captive portal"], answer:1, explain:"<strong>WPA3-Enterprise</strong> is the current strongest option, adding SAE-based protections, mandatory management-frame protection, and 802.1X authentication for individualized keys.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>WEP</b>: WEP is broken and trivially cracked; it must never be used.</span><span class='qd'><b>WPA2-Personal</b>: WPA2-Personal uses a shared passphrase and lacks WPA3's SAE and individualized authentication.</span><span class='qd'><b>Open with a captive portal</b>: an open network provides no over-the-air encryption regardless of the portal.</span>" },
{ id:"D4-019", domain:4, obj:"4.1", diff:"hard", q:"WPA3 replaced WPA2's PSK handshake to resist offline dictionary attacks. Which key-exchange mechanism does WPA3-Personal use to achieve this?", options:["TKIP","WEP RC4 keystream","Simultaneous Authentication of Equals (SAE)","EAP-MD5"], answer:2, explain:"<strong>Simultaneous Authentication of Equals (SAE)</strong> is the dragonfly-based handshake in WPA3-Personal that provides forward secrecy and resists offline password-guessing.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>TKIP</b>: TKIP is a legacy WPA cipher, deprecated and not the WPA3 handshake.</span><span class='qd'><b>WEP RC4 keystream</b>: RC4 in WEP is obsolete and insecure, unrelated to SAE.</span><span class='qd'><b>EAP-MD5</b>: EAP-MD5 is a weak enterprise EAP method, not the Personal-mode handshake.</span>" },
{ id:"D4-020", domain:4, obj:"4.1", diff:"medium", q:"A hospital deploying 5G private cellular for medical devices asks which security property is MOST improved over 4G/LTE. Which answer is BEST?", options:["5G removes the need for authentication","5G eliminates all radio interference","5G makes VPNs unnecessary","5G introduces stronger subscriber-identity encryption (concealed SUPI/SUCI)"], answer:3, explain:"<strong>5G introduces stronger subscriber-identity encryption (concealed SUPI/SUCI)</strong> so the permanent subscriber identifier is not sent in the clear, mitigating IMSI-catcher tracking that plagued earlier generations.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>5G removes the need for authentication</b>: 5G strengthens mutual authentication rather than removing it.</span><span class='qd'><b>5G eliminates all radio interference</b>: RF interference is a physical reality no standard eliminates.</span><span class='qd'><b>5G makes VPNs unnecessary</b>: end-to-end application encryption/VPNs remain best practice even on 5G.</span>" },
{ id:"D4-021", domain:4, obj:"4.1", diff:"easy", q:"Which addressing scheme uses 128-bit addresses and was designed in part to solve IPv4 address exhaustion?", options:["IPv6","IPv4","MAC addressing","APIPA"], answer:0, explain:"<strong>IPv6</strong> uses 128-bit addresses, providing a vastly larger address space and built-in features like IPsec support.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>IPv4</b>: IPv4 uses 32-bit addresses and is the scheme suffering exhaustion.</span><span class='qd'><b>MAC addressing</b>: MAC addresses are 48-bit Layer 2 hardware identifiers, not a Layer 3 scheme.</span><span class='qd'><b>APIPA</b>: APIPA assigns link-local 169.254.x.x IPv4 addresses when DHCP fails; it is not a 128-bit scheme.</span>" },
{ id:"D4-022", domain:4, obj:"4.1", diff:"medium", q:"An engineer must secure email transport between mail servers so messages are encrypted in transit. Which mechanism BEST accomplishes this at the transport level?", options:["S/MIME on each message","STARTTLS / SMTP over TLS","POP3 without encryption","Open relay configuration"], answer:1, explain:"<strong>STARTTLS / SMTP over TLS</strong> opportunistically or explicitly negotiates TLS between mail servers, encrypting the SMTP conversation in transit.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>S/MIME on each message</b>: S/MIME provides end-to-end message encryption/signing but is content-level, not transport-level, and requires per-user certificates.</span><span class='qd'><b>POP3 without encryption</b>: POP3 is a client retrieval protocol and, unencrypted, exposes credentials and mail.</span><span class='qd'><b>Open relay configuration</b>: an open relay is a serious misconfiguration that enables spam, not a security control.</span>" },
{ id:"D4-023", domain:4, obj:"4.1", diff:"medium", q:"Which protocol suite provides confidentiality and integrity for VoIP media streams (the actual audio) rather than just call signaling?", options:["SIP","RTP","SRTP","H.323 gatekeeper"], answer:2, explain:"<strong>SRTP</strong> (Secure Real-time Transport Protocol) encrypts and authenticates the media stream carrying the audio/video payload.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>SIP</b>: SIP is a signaling protocol for setting up calls; it is secured by SIP-TLS, but it does not carry media.</span><span class='qd'><b>RTP</b>: plain RTP carries media but without encryption or authentication.</span><span class='qd'><b>H.323 gatekeeper</b>: an H.323 gatekeeper manages call admission/addressing, not media encryption.</span>" },
{ id:"D4-024", domain:4, obj:"4.1", diff:"hard", q:"A network is being segmented so that a compromise of an IoT device cannot reach the finance servers. Which approach is the MOST effective architectural control?", options:["Place all devices on one flat VLAN for simplicity","Rely solely on a perimeter firewall","Increase the DHCP scope size","Implement microsegmentation with least-privilege east-west firewall policies"], answer:3, explain:"<strong>Implement microsegmentation with least-privilege east-west firewall policies</strong> restricts lateral movement so a compromised IoT device cannot traverse to finance systems, aligning with zero-trust principles.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Place all devices on one flat VLAN for simplicity</b>: a flat network maximizes lateral movement, the opposite of the goal.</span><span class='qd'><b>Rely solely on a perimeter firewall</b>: a perimeter firewall does nothing to stop east-west traffic once inside.</span><span class='qd'><b>Increase the DHCP scope size</b>: scope size affects address availability, not segmentation or lateral-movement risk.</span>" },
{ id:"D4-025", domain:4, obj:"4.1", diff:"medium", q:"An architect wants to verify that traffic between two internal segments is inspected and controlled. Which device placement BEST enforces policy between VLANs?", options:["An internal (inter-VLAN) firewall or Layer 3 firewall","A hub between the VLANs","A longer patch cable","A wireless repeater"], answer:0, explain:"<strong>An internal (inter-VLAN) firewall or Layer 3 firewall</strong> forces inter-segment traffic through a policy-enforcement point where it can be inspected and filtered.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A hub between the VLANs</b>: a hub blindly repeats traffic and enforces no policy.</span><span class='qd'><b>A longer patch cable</b>: cabling length has no bearing on traffic inspection.</span><span class='qd'><b>A wireless repeater</b>: a repeater extends coverage but performs no filtering.</span>" },
{ id:"D4-026", domain:4, obj:"4.1", diff:"easy", q:"Which protocol resolves a known IP address to its corresponding MAC address on a local network?", options:["DNS","ARP","DHCP","NTP"], answer:1, explain:"<strong>ARP</strong> (Address Resolution Protocol) maps a known IPv4 address to the MAC address needed for Layer 2 delivery on the local segment.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>DNS</b>: DNS resolves hostnames to IP addresses, not IP to MAC.</span><span class='qd'><b>DHCP</b>: DHCP assigns IP configuration to hosts, not address resolution to MAC.</span><span class='qd'><b>NTP</b>: NTP synchronizes clocks and has no addressing role.</span>" },
{ id:"D4-027", domain:4, obj:"4.1", diff:"hard", q:"An attacker sends forged ARP replies to associate the gateway's IP with the attacker's MAC, intercepting traffic. Which control MOST directly mitigates this ARP spoofing?", options:["Increasing switch port speed","A larger routing table","Dynamic ARP Inspection (DAI) with DHCP snooping","Disabling QoS"], answer:2, explain:"<strong>Dynamic ARP Inspection (DAI) with DHCP snooping</strong> validates ARP packets against a trusted binding table, dropping forged replies that would enable the on-path attack.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Increasing switch port speed</b>: link speed has no effect on ARP validation.</span><span class='qd'><b>A larger routing table</b>: routing capacity does not stop Layer 2 ARP forgery.</span><span class='qd'><b>Disabling QoS</b>: QoS handles prioritization and is irrelevant to ARP integrity.</span>" },
{ id:"D4-028", domain:4, obj:"4.1", diff:"medium", q:"A design team wants to prevent Layer 2 loops that could cause broadcast storms in a switched network. Which protocol is intended for this?", options:["OSPF","BGP","HSRP","Spanning Tree Protocol (STP/RSTP)"], answer:3, explain:"<strong>Spanning Tree Protocol (STP/RSTP)</strong> logically blocks redundant Layer 2 paths to prevent loops and broadcast storms while keeping a loop-free topology.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>OSPF</b>: OSPF is a Layer 3 routing protocol and does not manage Layer 2 loops.</span><span class='qd'><b>BGP</b>: BGP is the inter-domain routing protocol of the Internet, not a loop-prevention mechanism for switches.</span><span class='qd'><b>HSRP</b>: HSRP provides gateway redundancy, not Layer 2 loop prevention.</span>" },
{ id:"D4-029", domain:4, obj:"4.1", diff:"medium", q:"To defend against rogue devices spoofing DHCP servers on access ports, which switch feature should be enabled?", options:["DHCP snooping","Port mirroring","Jumbo frames","Proxy ARP"], answer:0, explain:"<strong>DHCP snooping</strong> designates trusted ports and drops DHCP server responses from untrusted ports, blocking rogue DHCP servers.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Port mirroring</b>: mirroring copies traffic for analysis and does not block rogue DHCP.</span><span class='qd'><b>Jumbo frames</b>: jumbo frames adjust MTU and have no security filtering function.</span><span class='qd'><b>Proxy ARP</b>: proxy ARP answers ARP on behalf of another host and can even introduce risk, not prevent rogue DHCP.</span>" },
{ id:"D4-030", domain:4, obj:"4.1", diff:"easy", q:"Which technology allows many internal private IP hosts to share one or a few public IP addresses when accessing the Internet?", options:["DNS","NAT/PAT","STP","VLAN"], answer:1, explain:"<strong>NAT/PAT</strong> translates private internal addresses to public addresses (and multiplexes many hosts behind one public IP via port translation).<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>DNS</b>: DNS resolves names to addresses and does not translate addresses.</span><span class='qd'><b>STP</b>: STP prevents Layer 2 loops and has no addressing translation role.</span><span class='qd'><b>VLAN</b>: a VLAN segments a broadcast domain but does not translate public/private addresses.</span>" },
{ id:"D4-031", domain:4, obj:"4.1", diff:"medium", q:"A security manager wants a design that assumes no implicit trust based on network location, requiring verification for every access request. This philosophy is BEST described as:", options:["Perimeter-based (castle-and-moat) security","Flat network design","Zero Trust Architecture","Security through obscurity"], answer:2, explain:"<strong>Zero Trust Architecture</strong> removes implicit trust from network location and continuously verifies identity, device posture, and context for each request.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Perimeter-based (castle-and-moat) security</b>: that model trusts insiders once past the perimeter, the opposite of zero trust.</span><span class='qd'><b>Flat network design</b>: a flat network provides no segmentation and encourages implicit trust.</span><span class='qd'><b>Security through obscurity</b>: obscurity hides details but does not enforce continuous verification.</span>" },
{ id:"D4-032", domain:4, obj:"4.1", diff:"hard", q:"An organization implementing zero trust wants each access decision informed by real-time device health, user identity, and request context. Which component makes the allow/deny decision?", options:["Policy Enforcement Point (PEP)","Default gateway","DNS resolver","Policy Decision Point (PDP)"], answer:3, explain:"<strong>Policy Decision Point (PDP)</strong> evaluates identity, device posture, and context against policy and issues the access decision that the enforcement point then applies.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Policy Enforcement Point (PEP)</b>: the PEP enforces the decision but does not compute it.</span><span class='qd'><b>Default gateway</b>: the gateway routes packets and makes no policy decisions.</span><span class='qd'><b>DNS resolver</b>: the resolver answers name queries and is unrelated to access decisions.</span>" },
{ id:"D4-033", domain:4, obj:"4.1", diff:"medium", q:"Which secure protocol replaces plaintext SNMPv1/v2c community strings with authentication and encryption for network management?", options:["SNMPv3","Telnet","TFTP","Syslog over UDP"], answer:0, explain:"<strong>SNMPv3</strong> adds authentication and privacy (encryption) with per-user security, replacing the cleartext community strings of earlier versions.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Telnet</b>: Telnet is an unencrypted remote-terminal protocol, not a management framework.</span><span class='qd'><b>TFTP</b>: TFTP transfers files without authentication or encryption.</span><span class='qd'><b>Syslog over UDP</b>: plain syslog over UDP sends log data unencrypted and unauthenticated.</span>" },
{ id:"D4-034", domain:4, obj:"4.1", diff:"medium", q:"An architect must select a routing protocol for a large enterprise interior network that converges quickly and uses link-state calculations. Which is the BEST fit?", options:["RIPv1","OSPF","Static routes only","BGP for internal routing"], answer:1, explain:"<strong>OSPF</strong> is a link-state interior gateway protocol that scales well, converges quickly, and supports hierarchical areas for large enterprises.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>RIPv1</b>: RIPv1 is a legacy distance-vector protocol with a 15-hop limit and slow convergence.</span><span class='qd'><b>Static routes only</b>: static routing does not scale or converge automatically in a large dynamic network.</span><span class='qd'><b>BGP for internal routing</b>: BGP is designed for inter-domain routing between autonomous systems, not typical interior enterprise routing.</span>" },
{ id:"D4-035", domain:4, obj:"4.1", diff:"easy", q:"Which port is used by DNS for standard name-resolution queries?", options:["Port 443","Port 25","Port 53","Port 161"], answer:2, explain:"<strong>Port 53</strong> is used by DNS, typically UDP 53 for queries and TCP 53 for zone transfers and large responses.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Port 443</b>: 443 is HTTPS, not DNS.</span><span class='qd'><b>Port 25</b>: 25 is SMTP for mail relay.</span><span class='qd'><b>Port 161</b>: 161 is SNMP for network management.</span>" },
{ id:"D4-036", domain:4, obj:"4.1", diff:"medium", q:"A team must protect a wireless deployment from an evil-twin access point that mimics the corporate SSID. Which control MOST directly addresses this threat?", options:["Broadcasting the SSID more frequently","Lowering transmit power to zero","Using a longer DHCP lease","Enabling WPA3-Enterprise with mutual 802.1X authentication"], answer:3, explain:"<strong>Enabling WPA3-Enterprise with mutual 802.1X authentication</strong> lets clients validate the network via server certificates, so a rogue evil-twin AP cannot successfully impersonate the corporate network.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Broadcasting the SSID more frequently</b>: SSID broadcast frequency does nothing to authenticate the AP.</span><span class='qd'><b>Lowering transmit power to zero</b>: zero power disables legitimate service and does not stop the attacker's AP.</span><span class='qd'><b>Using a longer DHCP lease</b>: DHCP lease length is irrelevant to AP authentication.</span>" },
{ id:"D4-037", domain:4, obj:"4.1", diff:"hard", q:"An enterprise uses 802.1X for wired port authentication. Which EAP method is generally considered the STRONGEST because it requires mutual certificate-based authentication of both client and server?", options:["EAP-TLS","EAP-MD5","PEAP with weak password policy","LEAP"], answer:0, explain:"<strong>EAP-TLS</strong> uses client and server certificates for mutual authentication, providing the strongest assurance and resistance to credential theft.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>EAP-MD5</b>: EAP-MD5 offers only one-way, hash-based authentication and is easily attacked.</span><span class='qd'><b>PEAP with weak password policy</b>: PEAP tunnels inner authentication but weak passwords undermine it and it lacks client certificates.</span><span class='qd'><b>LEAP</b>: LEAP is a Cisco-proprietary legacy method vulnerable to dictionary attacks.</span>" },
{ id:"D4-038", domain:4, obj:"4.1", diff:"medium", q:"Which statement correctly distinguishes TCP from UDP for an application choosing a transport?", options:["UDP guarantees ordered delivery; TCP does not","TCP is connection-oriented and reliable; UDP is connectionless and lower overhead","Both establish a three-way handshake","TCP is always faster than UDP for real-time media"], answer:1, explain:"<strong>TCP is connection-oriented and reliable; UDP is connectionless and lower overhead</strong> correctly summarizes the trade-off: TCP guarantees delivery at higher overhead, while UDP is lightweight and better for real-time traffic that tolerates loss.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>UDP guarantees ordered delivery; TCP does not</b>: this is reversed; TCP orders delivery, UDP does not.</span><span class='qd'><b>Both establish a three-way handshake</b>: only TCP performs the three-way handshake.</span><span class='qd'><b>TCP is always faster than UDP for real-time media</b>: TCP's retransmissions add latency, making UDP generally preferable for real-time media.</span>" },
{ id:"D4-039", domain:4, obj:"4.1", diff:"easy", q:"Which device operates at Layer 1 and simply repeats incoming signals to all ports, creating a single collision domain?", options:["Router","Layer 3 switch","Hub","Firewall"], answer:2, explain:"<strong>Hub</strong> is a Layer 1 device that repeats bits to all ports, placing all connected hosts in one collision domain.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Router</b>: a router is a Layer 3 device that segments broadcast domains.</span><span class='qd'><b>Layer 3 switch</b>: a Layer 3 switch forwards intelligently and separates collision domains per port.</span><span class='qd'><b>Firewall</b>: a firewall filters traffic and is not a signal repeater.</span>" },
{ id:"D4-040", domain:4, obj:"4.1", diff:"hard", q:"A cloud architect must connect an on-premises data center to a public-cloud VPC with encrypted, private connectivity that does not traverse the public Internet path unprotected. Which combination is BEST?", options:["A plain HTTP connection over the Internet","Telnet to the cloud console","FTP file transfer only","An IPsec site-to-site VPN, optionally over a dedicated interconnect"], answer:3, explain:"<strong>An IPsec site-to-site VPN, optionally over a dedicated interconnect</strong> provides encrypted, authenticated connectivity between the data center and VPC, and a private interconnect can further isolate the path.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A plain HTTP connection over the Internet</b>: unencrypted HTTP exposes traffic and provides no site-to-site tunnel.</span><span class='qd'><b>Telnet to the cloud console</b>: Telnet is insecure and is a management protocol, not a network interconnect.</span><span class='qd'><b>FTP file transfer only</b>: FTP is a file protocol, not an encrypted network-to-network connection.</span>" },
{ id:"D4-041", domain:4, obj:"4.1", diff:"medium", q:"Which OSI layer would a security professional associate with a SYN flood attack that exhausts a server's half-open connection table?", options:["Layer 4 (Transport)","Layer 2 (Data Link)","Layer 6 (Presentation)","Layer 1 (Physical)"], answer:0, explain:"<strong>Layer 4 (Transport)</strong> is where TCP operates, and a SYN flood abuses the TCP three-way handshake to fill the half-open connection table.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Layer 2 (Data Link)</b>: Layer 2 handles frames/MAC and is not where TCP handshakes occur.</span><span class='qd'><b>Layer 6 (Presentation)</b>: Layer 6 handles data formatting, not connection state.</span><span class='qd'><b>Layer 1 (Physical)</b>: Layer 1 concerns signaling and cabling, not TCP state exhaustion.</span>" },
{ id:"D4-042", domain:4, obj:"4.1", diff:"medium", q:"A designer wants encrypted, authenticated file transfer over a single SSH session. Which protocol is the BEST choice?", options:["FTP","SFTP","TFTP","HTTP"], answer:1, explain:"<strong>SFTP</strong> runs file transfer inside an SSH session, providing encryption and authentication over a single secure channel on port 22.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>FTP</b>: FTP transfers data and credentials in cleartext.</span><span class='qd'><b>TFTP</b>: TFTP is unauthenticated and unencrypted.</span><span class='qd'><b>HTTP</b>: plain HTTP is unencrypted and not a dedicated secure file-transfer protocol.</span>" },
{ id:"D4-043", domain:4, obj:"4.1", diff:"hard", q:"An architect evaluates FTPS versus SFTP. Which statement is the MOST accurate technical distinction?", options:["FTPS uses SSH; SFTP uses TLS","They are identical protocols with different names","SFTP runs over SSH (one port), while FTPS adds TLS to FTP and can require multiple ports","Neither encrypts data"], answer:2, explain:"<strong>SFTP runs over SSH (one port), while FTPS adds TLS to FTP and can require multiple ports</strong> correctly distinguishes them: SFTP is simpler for firewalls (single port 22), whereas FTPS inherits FTP's separate control/data channels.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>FTPS uses SSH; SFTP uses TLS</b>: this is reversed; SFTP uses SSH and FTPS uses TLS.</span><span class='qd'><b>They are identical protocols with different names</b>: they use different underlying security layers and port behavior.</span><span class='qd'><b>Neither encrypts data</b>: both encrypt data when properly configured.</span>" },
{ id:"D4-044", domain:4, obj:"4.1", diff:"medium", q:"A converged network carries storage traffic (iSCSI) alongside data. Which control BEST isolates storage traffic to reduce contention and exposure?", options:["Run iSCSI over the public Internet unencrypted","Disable all VLANs","Use a hub for storage traffic","Place iSCSI on a dedicated, isolated storage VLAN/network"], answer:3, explain:"<strong>Place iSCSI on a dedicated, isolated storage VLAN/network</strong> separates latency-sensitive, sensitive storage traffic from general data, reducing contention and limiting exposure.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Run iSCSI over the public Internet unencrypted</b>: exposing storage traffic to the Internet without encryption is a serious risk.</span><span class='qd'><b>Disable all VLANs</b>: removing segmentation increases contention and exposure.</span><span class='qd'><b>Use a hub for storage traffic</b>: a hub shares bandwidth and creates collisions, harming storage performance.</span>" },
{ id:"D4-045", domain:4, obj:"4.1", diff:"easy", q:"Which protocol synchronizes time across network devices, an important dependency for accurate logs and certificate validation?", options:["NTP","SMTP","SNMP","LDAP"], answer:0, explain:"<strong>NTP</strong> (Network Time Protocol) synchronizes clocks, which is essential for correlating logs and validating time-sensitive certificates and tokens.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>SMTP</b>: SMTP relays email and has no timing function.</span><span class='qd'><b>SNMP</b>: SNMP manages and monitors devices, not clock synchronization.</span><span class='qd'><b>LDAP</b>: LDAP is a directory-access protocol, unrelated to time sync.</span>" },
{ id:"D4-046", domain:4, obj:"4.1", diff:"hard", q:"A security architect notes that an unauthenticated NTP server could be spoofed to skew device clocks and break certificate/token validation. Which mitigation is BEST?", options:["Ignore time drift as harmless","Use authenticated NTP (symmetric keys or NTS) from trusted, redundant sources","Set clocks manually once per year","Disable logging to avoid timestamps"], answer:1, explain:"<strong>Use authenticated NTP (symmetric keys or NTS) from trusted, redundant sources</strong> ensures time updates are genuine, protecting log integrity and certificate/token validity from clock-skew attacks.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Ignore time drift as harmless</b>: skewed time breaks security controls and forensic correlation.</span><span class='qd'><b>Set clocks manually once per year</b>: manual setting drifts quickly and does not scale.</span><span class='qd'><b>Disable logging to avoid timestamps</b>: disabling logs destroys accountability and detection.</span>" },
{ id:"D4-047", domain:4, obj:"4.2", diff:"easy", q:"Which cabling medium is MOST resistant to electromagnetic interference and eavesdropping via induction?", options:["Unshielded twisted pair (UTP)","Coaxial cable","Fiber-optic cable","Shielded twisted pair (STP)"], answer:2, explain:"<strong>Fiber-optic cable</strong> carries light rather than electrical signals, making it immune to EMI and extremely difficult to tap without detection.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Unshielded twisted pair (UTP)</b>: UTP is the most susceptible to EMI and crosstalk.</span><span class='qd'><b>Coaxial cable</b>: coax carries electrical signals and can radiate and be tapped.</span><span class='qd'><b>Shielded twisted pair (STP)</b>: STP resists EMI better than UTP but still uses copper and can be tapped.</span>" },
{ id:"D4-048", domain:4, obj:"4.2", diff:"medium", q:"An organization wants to ensure only healthy, compliant devices can connect to the corporate network, checking posture before granting access. Which technology provides this?", options:["Load balancer","Reverse proxy","Content delivery network (CDN)","Network Access Control (NAC)"], answer:3, explain:"<strong>Network Access Control (NAC)</strong> authenticates devices and evaluates posture (patch level, AV status, configuration) before granting or restricting network access.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Load balancer</b>: a load balancer distributes traffic across servers and does not assess endpoint posture.</span><span class='qd'><b>Reverse proxy</b>: a reverse proxy fronts servers for clients but does not enforce device admission control.</span><span class='qd'><b>Content delivery network (CDN)</b>: a CDN caches content near users and has no NAC function.</span>" },
{ id:"D4-049", domain:4, obj:"4.2", diff:"medium", q:"A stateful inspection firewall differs from a simple packet filter primarily because it:", options:["Tracks the state of active connections and allows return traffic accordingly","Only checks source and destination ports","Cannot filter by IP address","Operates only at Layer 1"], answer:0, explain:"<strong>Tracks the state of active connections and allows return traffic accordingly</strong> is the defining feature of stateful inspection: it maintains a connection table so legitimate replies are permitted without broad static rules.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Only checks source and destination ports</b>: that describes a basic stateless packet filter, not stateful inspection.</span><span class='qd'><b>Cannot filter by IP address</b>: stateful firewalls filter by IP, port, and connection state.</span><span class='qd'><b>Operates only at Layer 1</b>: firewalls operate at Layers 3-4 and often higher, not Layer 1.</span>" },
{ id:"D4-050", domain:4, obj:"4.2", diff:"hard", q:"A security team must inspect application-layer content, decrypt TLS, and enforce user- and app-aware policies with integrated IPS. Which firewall type is the BEST fit?", options:["Stateless packet filter","Next-generation firewall (NGFW)","A Layer 2 switch ACL","A basic screening router"], answer:1, explain:"<strong>Next-generation firewall (NGFW)</strong> combines stateful inspection with application awareness, user identity, TLS decryption, and integrated IPS, matching all the stated requirements.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Stateless packet filter</b>: it only checks headers and cannot do application-aware inspection or IPS.</span><span class='qd'><b>A Layer 2 switch ACL</b>: switch ACLs filter at Layers 2-4 without deep application inspection.</span><span class='qd'><b>A basic screening router</b>: a screening router applies simple ACLs, lacking NGFW capabilities.</span>" },
{ id:"D4-051", domain:4, obj:"4.2", diff:"medium", q:"An enterprise wants outbound web requests proxied, filtered, and logged, hiding internal clients from external servers. Which component provides this?", options:["Reverse proxy","Layer 2 switch","Forward (web) proxy","DHCP server"], answer:2, explain:"<strong>Forward (web) proxy</strong> sits between internal clients and the Internet, filtering, caching, and logging outbound requests while masking client identities.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Reverse proxy</b>: a reverse proxy fronts internal servers for external clients, the opposite direction.</span><span class='qd'><b>Layer 2 switch</b>: a switch forwards frames and does not proxy or filter web content.</span><span class='qd'><b>DHCP server</b>: DHCP assigns addresses and does not proxy traffic.</span>" },
{ id:"D4-052", domain:4, obj:"4.2", diff:"easy", q:"Which endpoint security capability continuously records endpoint activity to detect, investigate, and respond to threats on hosts?", options:["DHCP","NAT","STP","EDR (Endpoint Detection and Response)"], answer:3, explain:"<strong>EDR (Endpoint Detection and Response)</strong> monitors and records endpoint behavior to detect malicious activity and enable investigation and response.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>DHCP</b>: DHCP assigns IP addresses and has no threat-detection function.</span><span class='qd'><b>NAT</b>: NAT translates addresses; it is not an endpoint defense.</span><span class='qd'><b>STP</b>: STP prevents Layer 2 loops and is unrelated to endpoint security.</span>" },
{ id:"D4-053", domain:4, obj:"4.2", diff:"medium", q:"An architect must place a public-facing web server so that, if compromised, it cannot directly reach the internal database tier. Which placement is BEST?", options:["In a DMZ (screened subnet) separated by firewalls","On the internal LAN with the database","Directly on the Internet with no firewall","On the management VLAN"], answer:0, explain:"<strong>In a DMZ (screened subnet) separated by firewalls</strong> isolates the exposed server so inbound Internet traffic reaches only the DMZ, and tight rules prevent it from pivoting to the internal database.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>On the internal LAN with the database</b>: co-locating a public server with the database removes isolation and invites lateral movement.</span><span class='qd'><b>Directly on the Internet with no firewall</b>: no firewall leaves the server fully exposed and unmonitored.</span><span class='qd'><b>On the management VLAN</b>: placing a public server on the management network exposes sensitive admin infrastructure.</span>" },
{ id:"D4-054", domain:4, obj:"4.2", diff:"hard", q:"A network engineer must prevent a single compromised switch port from spoofing many MAC addresses to exhaust the CAM table (a MAC flooding attack). Which control is MOST appropriate?", options:["Increasing the VLAN count","Port security limiting MAC addresses per port","Enabling proxy ARP","Disabling logging"], answer:1, explain:"<strong>Port security limiting MAC addresses per port</strong> caps how many source MACs a port accepts and can shut down or restrict the port on violation, defeating MAC flooding.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Increasing the VLAN count</b>: more VLANs do not limit MAC learning on a single port.</span><span class='qd'><b>Enabling proxy ARP</b>: proxy ARP is unrelated and can introduce other risks.</span><span class='qd'><b>Disabling logging</b>: disabling logging reduces visibility and does not stop the attack.</span>" },
{ id:"D4-055", domain:4, obj:"4.2", diff:"medium", q:"Which detective control passively copies and analyzes network traffic to identify malicious patterns but does not block traffic inline?", options:["IPS in inline mode","A stateful firewall","IDS (Intrusion Detection System)","A NAT gateway"], answer:2, explain:"<strong>IDS (Intrusion Detection System)</strong> monitors a copy of traffic and alerts on suspicious activity but, being out-of-band, does not block the traffic itself.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>IPS in inline mode</b>: an inline IPS actively blocks, making it preventive rather than purely detective.</span><span class='qd'><b>A stateful firewall</b>: a firewall enforces allow/deny rules inline, not passive detection.</span><span class='qd'><b>A NAT gateway</b>: NAT translates addresses and performs no intrusion analysis.</span>" },
{ id:"D4-056", domain:4, obj:"4.2", diff:"hard", q:"A security team wants a control that both detects AND actively blocks malicious packets in real time as they traverse the network. Which is the BEST choice?", options:["An out-of-band IDS on a SPAN port","A syslog server","A honeypot","An inline IPS (Intrusion Prevention System)"], answer:3, explain:"<strong>An inline IPS (Intrusion Prevention System)</strong> sits in the traffic path and can drop or reset malicious flows in real time, providing both detection and prevention.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>An out-of-band IDS on a SPAN port</b>: an out-of-band IDS only alerts and cannot block inline.</span><span class='qd'><b>A syslog server</b>: a syslog server collects logs and does not inspect or block traffic.</span><span class='qd'><b>A honeypot</b>: a honeypot lures attackers for study but does not block production traffic.</span>" },
{ id:"D4-057", domain:4, obj:"4.2", diff:"easy", q:"Which device distributes incoming client requests across multiple backend servers to improve availability and performance?", options:["Load balancer","Repeater","Media converter","Patch panel"], answer:0, explain:"<strong>Load balancer</strong> spreads traffic across a pool of servers, improving availability, scalability, and performance.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Repeater</b>: a repeater regenerates a signal to extend distance, not distribute load.</span><span class='qd'><b>Media converter</b>: a media converter changes signal media (e.g., copper to fiber), not balance load.</span><span class='qd'><b>Patch panel</b>: a patch panel is a passive cabling junction, not an active distributor.</span>" },
{ id:"D4-058", domain:4, obj:"4.2", diff:"medium", q:"An organization wants to protect a public web application from SQL injection and cross-site scripting at the application layer. Which control is BEST suited?", options:["A Layer 3 packet filter","A Web Application Firewall (WAF)","A DHCP relay","A Layer 2 switch"], answer:1, explain:"<strong>A Web Application Firewall (WAF)</strong> inspects HTTP/HTTPS requests and blocks application-layer attacks like SQL injection and XSS that lower-layer devices cannot see.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A Layer 3 packet filter</b>: a packet filter only sees IP/port headers, not application payloads.</span><span class='qd'><b>A DHCP relay</b>: a DHCP relay forwards address requests and has no inspection role.</span><span class='qd'><b>A Layer 2 switch</b>: a switch forwards frames and cannot parse web-application content.</span>" },
{ id:"D4-059", domain:4, obj:"4.2", diff:"medium", q:"Which practice BEST hardens infrastructure devices (routers/switches) against unauthorized management access?", options:["Leaving default credentials for convenience","Enabling Telnet on all interfaces","Using encrypted management (SSH/HTTPS), disabling unused services, and strong unique credentials","Sharing one admin password across all devices"], answer:2, explain:"<strong>Using encrypted management (SSH/HTTPS), disabling unused services, and strong unique credentials</strong> reduces the attack surface and protects administrative sessions, aligning with secure operation of infrastructure.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Leaving default credentials for convenience</b>: default credentials are widely known and trivially exploited.</span><span class='qd'><b>Enabling Telnet on all interfaces</b>: Telnet transmits credentials in cleartext.</span><span class='qd'><b>Sharing one admin password across all devices</b>: a shared password destroys accountability and enables broad compromise.</span>" },
{ id:"D4-060", domain:4, obj:"4.2", diff:"hard", q:"A design must ensure management traffic to network devices is separated from user data traffic to reduce the risk of a compromised host reaching device management. Which approach is BEST?", options:["Managing devices over the same user VLAN","Using Telnet from any workstation","Disabling all authentication for speed","A dedicated out-of-band management network/VLAN"], answer:3, explain:"<strong>A dedicated out-of-band management network/VLAN</strong> isolates administrative access so a compromised user host cannot reach the management plane, a core secure-operations practice.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Managing devices over the same user VLAN</b>: sharing the user VLAN exposes management to compromised endpoints.</span><span class='qd'><b>Using Telnet from any workstation</b>: Telnet is unencrypted and broad access widens exposure.</span><span class='qd'><b>Disabling all authentication for speed</b>: removing authentication is a critical vulnerability.</span>" },
{ id:"D4-061", domain:4, obj:"4.2", diff:"easy", q:"Which term describes an isolated network segment created specifically to lure and study attackers?", options:["Honeynet","Backbone","Demarc","Trunk"], answer:0, explain:"<strong>Honeynet</strong> is a decoy network segment designed to attract, contain, and study attacker behavior without exposing production assets.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Backbone</b>: a backbone is the high-capacity core of a network, not a decoy.</span><span class='qd'><b>Demarc</b>: the demarcation point is where provider responsibility ends, not a trap.</span><span class='qd'><b>Trunk</b>: a trunk carries multiple VLANs between switches and is not a decoy.</span>" },
{ id:"D4-062", domain:4, obj:"4.2", diff:"medium", q:"A company wants to prevent sensitive data from leaving the network via email or web uploads. Which control category is the BEST fit?", options:["Load balancing","Data Loss Prevention (DLP)","NAT","QoS"], answer:1, explain:"<strong>Data Loss Prevention (DLP)</strong> inspects content in motion and blocks or alerts when sensitive data is being exfiltrated through channels like email and web uploads.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Load balancing</b>: load balancing distributes traffic and does not inspect content for leakage.</span><span class='qd'><b>NAT</b>: NAT translates addresses and cannot detect sensitive-data exfiltration.</span><span class='qd'><b>QoS</b>: QoS prioritizes traffic and has no content-inspection function.</span>" },
{ id:"D4-063", domain:4, obj:"4.2", diff:"hard", q:"An engineer must protect against VLAN hopping via double-tagging. Which switch configuration is MOST effective?", options:["Enable DTP auto on all ports","Use VLAN 1 as the native VLAN for all trunks","Set the native VLAN to an unused VLAN and explicitly tag it, and disable dynamic trunking (DTP)","Disable port security"], answer:2, explain:"<strong>Set the native VLAN to an unused VLAN and explicitly tag it, and disable dynamic trunking (DTP)</strong> removes the conditions double-tagging exploits and prevents access ports from negotiating into trunks.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Enable DTP auto on all ports</b>: auto-negotiation can let an attacker form a trunk, enabling VLAN hopping.</span><span class='qd'><b>Use VLAN 1 as the native VLAN for all trunks</b>: leaving the default native VLAN 1 untagged is exactly what double-tagging abuses.</span><span class='qd'><b>Disable port security</b>: disabling port security weakens defenses and does not address VLAN hopping.</span>" },
{ id:"D4-064", domain:4, obj:"4.2", diff:"medium", q:"Which control BEST ensures that removable media and USB endpoints cannot be used to exfiltrate data on corporate laptops?", options:["A faster CPU","A longer DHCP lease","More network bandwidth","Endpoint device control / port control policy"], answer:3, explain:"<strong>Endpoint device control / port control policy</strong> lets the organization restrict or block USB/removable media at the endpoint, preventing unauthorized data transfer.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A faster CPU</b>: processing speed has no bearing on removable-media control.</span><span class='qd'><b>A longer DHCP lease</b>: DHCP settings are unrelated to endpoint media policy.</span><span class='qd'><b>More network bandwidth</b>: bandwidth does not restrict local USB usage.</span>" },
{ id:"D4-065", domain:4, obj:"4.2", diff:"easy", q:"Which wireless component enables client devices to associate with the wired network and typically enforces the SSID's security settings?", options:["Access point (AP)","Patch panel","Media converter","Serial console"], answer:0, explain:"<strong>Access point (AP)</strong> bridges wireless clients to the wired LAN and enforces the SSID's authentication and encryption settings.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Patch panel</b>: a patch panel is passive copper termination, not a wireless bridge.</span><span class='qd'><b>Media converter</b>: a media converter changes physical media type, not wireless association.</span><span class='qd'><b>Serial console</b>: a serial console is for out-of-band device management, not client association.</span>" },
{ id:"D4-066", domain:4, obj:"4.2", diff:"medium", q:"A security architect wants to detect and analyze traffic on a switched network by sending a copy of frames to a monitoring tool. Which switch feature enables this?", options:["Trunk pruning","Port mirroring (SPAN)","Jumbo frames","Broadcast suppression"], answer:1, explain:"<strong>Port mirroring (SPAN)</strong> copies traffic from selected ports/VLANs to a monitoring port so an IDS or analyzer can inspect it without being inline.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Trunk pruning</b>: pruning limits which VLANs traverse a trunk, not traffic copying.</span><span class='qd'><b>Jumbo frames</b>: jumbo frames change MTU and do not mirror traffic.</span><span class='qd'><b>Broadcast suppression</b>: broadcast suppression limits broadcast storms, not monitoring copies.</span>" },
{ id:"D4-067", domain:4, obj:"4.2", diff:"hard", q:"A firewall administrator must decide the BEST default rule posture for a new perimeter firewall. Which approach aligns with secure design?", options:["Default allow, block only known-bad traffic","Allow all outbound and inbound to simplify troubleshooting","Default deny (implicit deny) and explicitly permit only required traffic","Permit any-any and rely on the IDS"], answer:2, explain:"<strong>Default deny (implicit deny) and explicitly permit only required traffic</strong> embodies least privilege at the network boundary, minimizing attack surface by allowing only justified flows.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Default allow, block only known-bad traffic</b>: an allow-by-default posture leaves unknown threats permitted.</span><span class='qd'><b>Allow all outbound and inbound to simplify troubleshooting</b>: permitting everything defeats the firewall's purpose.</span><span class='qd'><b>Permit any-any and rely on the IDS</b>: an IDS only detects; it cannot compensate for an any-any allow rule.</span>" },
{ id:"D4-068", domain:4, obj:"4.2", diff:"medium", q:"Which statement BEST describes the role of a bastion host in a secured network architecture?", options:["An unpatched jump box left on the Internet","A backup power supply","A DNS caching server only","A hardened, exposed host designed to withstand attack and provide a controlled access point"], answer:3, explain:"<strong>A hardened, exposed host designed to withstand attack and provide a controlled access point</strong> defines a bastion host: minimized services, heavy hardening, and close monitoring because it sits at an exposed boundary.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>An unpatched jump box left on the Internet</b>: a bastion host must be hardened and patched, not neglected.</span><span class='qd'><b>A backup power supply</b>: that is a UPS, unrelated to network access control.</span><span class='qd'><b>A DNS caching server only</b>: a caching resolver is a specific service, not the bastion concept.</span>" },
{ id:"D4-069", domain:4, obj:"4.2", diff:"hard", q:"A CISO wants endpoint controls that go beyond signature antivirus to detect fileless and behavior-based attacks and enable centralized response across many hosts. Which solution BEST meets this?", options:["EDR/XDR with behavioral analytics and centralized response","Legacy signature-only AV","A host-based firewall alone","Manual log review weekly"], answer:0, explain:"<strong>EDR/XDR with behavioral analytics and centralized response</strong> detects behavior-based and fileless threats and lets responders contain endpoints centrally, exceeding signature AV capabilities.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Legacy signature-only AV</b>: signature AV misses fileless and novel behavioral attacks.</span><span class='qd'><b>A host-based firewall alone</b>: a host firewall filters connections but does not analyze endpoint behavior or orchestrate response.</span><span class='qd'><b>Manual log review weekly</b>: weekly manual review is too slow and unscalable for real-time threats.</span>" },
{ id:"D4-070", domain:4, obj:"4.2", diff:"medium", q:"Which cabling standard consideration is MOST important when running network cable through plenum air-handling spaces?", options:["Using the longest possible cable runs","Using plenum-rated (fire-resistant, low-smoke) cable","Choosing the cheapest cable regardless of rating","Using coaxial cable exclusively"], answer:1, explain:"<strong>Using plenum-rated (fire-resistant, low-smoke) cable</strong> is required by fire/life-safety codes in plenum spaces because burning non-rated cable releases toxic smoke into the air supply.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Using the longest possible cable runs</b>: long runs risk exceeding distance limits and do not address plenum safety.</span><span class='qd'><b>Choosing the cheapest cable regardless of rating</b>: ignoring fire ratings violates code and endangers life safety.</span><span class='qd'><b>Using coaxial cable exclusively</b>: coax choice does not satisfy plenum flame/smoke requirements by itself.</span>" },
{ id:"D4-071", domain:4, obj:"4.2", diff:"easy", q:"Which term describes the physical point where the telecom provider's responsibility ends and the customer's wiring begins?", options:["Default gateway","Broadcast domain","Demarcation point (demarc)","Root bridge"], answer:2, explain:"<strong>Demarcation point (demarc)</strong> is the boundary between the carrier's network and the customer premises equipment/wiring.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Default gateway</b>: the default gateway is the router hosts use to leave their subnet, not a provider boundary.</span><span class='qd'><b>Broadcast domain</b>: a broadcast domain is a logical Layer 2 boundary, not a provider demarcation.</span><span class='qd'><b>Root bridge</b>: the root bridge is the STP reference switch, unrelated to provider handoff.</span>" },
{ id:"D4-072", domain:4, obj:"4.2", diff:"medium", q:"A firewall rule set has grown to hundreds of rules with duplicates and shadowed entries. What is the BEST governance practice to address this over time?", options:["Never review rules once created","Add more any-any rules to simplify","Disable logging to speed processing","Perform periodic firewall rule reviews/recertification and remove stale rules"], answer:3, explain:"<strong>Perform periodic firewall rule reviews/recertification and remove stale rules</strong> keeps the policy accurate, removes shadowed/obsolete rules, and maintains least privilege as the environment changes.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Never review rules once created</b>: unreviewed rules accumulate risk and drift from need.</span><span class='qd'><b>Add more any-any rules to simplify</b>: any-any rules defeat the firewall's purpose.</span><span class='qd'><b>Disable logging to speed processing</b>: disabling logging removes the visibility needed to audit rules.</span>" },
{ id:"D4-073", domain:4, obj:"4.2", diff:"hard", q:"An organization wants to authenticate devices at the wired switch port before allowing network access, quarantining noncompliant devices. Which combination BEST delivers this?", options:["802.1X port-based authentication integrated with NAC","Static IP assignment only","MAC address filtering as the sole control","Open ports with a banner warning"], answer:0, explain:"<strong>802.1X port-based authentication integrated with NAC</strong> forces authentication at the port and lets NAC assess posture, placing noncompliant devices into a quarantine VLAN.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Static IP assignment only</b>: static IPs do not authenticate or assess devices.</span><span class='qd'><b>MAC address filtering as the sole control</b>: MAC filtering is easily spoofed and does not evaluate posture.</span><span class='qd'><b>Open ports with a banner warning</b>: a banner provides no enforcement.</span>" },
{ id:"D4-074", domain:4, obj:"4.2", diff:"medium", q:"Which practice BEST reduces the risk that infrastructure device firmware contains known exploitable vulnerabilities?", options:["Never updating firmware to avoid downtime","Applying vendor firmware updates through a tested patch-management process","Downloading firmware from random third-party sites","Disabling all logging"], answer:1, explain:"<strong>Applying vendor firmware updates through a tested patch-management process</strong> closes known vulnerabilities while validating changes to avoid outages, a core secure-operations discipline.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Never updating firmware to avoid downtime</b>: leaving known vulnerabilities unpatched invites compromise.</span><span class='qd'><b>Downloading firmware from random third-party sites</b>: untrusted firmware sources risk supply-chain tampering.</span><span class='qd'><b>Disabling all logging</b>: disabling logging reduces visibility and does not patch anything.</span>" },
{ id:"D4-075", domain:4, obj:"4.2", diff:"medium", q:"A security architect wants to ensure endpoints connecting via VPN meet minimum security posture before full network access. Which technology enforces this at connection time?", options:["A larger MTU","Round-robin DNS","Posture assessment / host checking in the VPN or NAC solution","A faster switch backplane"], answer:2, explain:"<strong>Posture assessment / host checking in the VPN or NAC solution</strong> evaluates patch level, AV status, and configuration before granting access, quarantining noncompliant endpoints.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A larger MTU</b>: MTU affects packet size, not posture enforcement.</span><span class='qd'><b>Round-robin DNS</b>: round-robin distributes queries and does not check host health.</span><span class='qd'><b>A faster switch backplane</b>: backplane speed does not assess endpoint compliance.</span>" },
{ id:"D4-076", domain:4, obj:"4.3", diff:"easy", q:"Which VPN technology provides a browser-based, clientless remote-access option for users to reach specific web applications securely?", options:["IPsec ESP tunnel only","Frame Relay","X.25","SSL/TLS VPN (clientless portal)"], answer:3, explain:"<strong>SSL/TLS VPN (clientless portal)</strong> lets users access permitted web applications through a browser without installing a full VPN client, simplifying remote access.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>IPsec ESP tunnel only</b>: IPsec typically requires a client and provides network-layer tunneling, not a clientless browser portal.</span><span class='qd'><b>Frame Relay</b>: Frame Relay is a legacy WAN technology, not a remote-access VPN.</span><span class='qd'><b>X.25</b>: X.25 is an obsolete packet-switching standard, not a modern VPN.</span>" },
{ id:"D4-077", domain:4, obj:"4.3", diff:"medium", q:"A remote-access VPN design must decide between full tunneling and split tunneling. From a security standpoint, which statement is MOST accurate?", options:["Full tunneling routes all traffic through corporate inspection, improving control but adding load","Split tunneling always improves security","Full tunneling bypasses all corporate controls","Split tunneling forces all traffic through the firewall"], answer:0, explain:"<strong>Full tunneling routes all traffic through corporate inspection, improving control but adding load</strong> correctly frames the trade-off: full tunnel maximizes visibility and policy enforcement at the cost of bandwidth on the corporate egress.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Split tunneling always improves security</b>: split tunneling sends some traffic outside corporate controls, generally reducing inspection.</span><span class='qd'><b>Full tunneling bypasses all corporate controls</b>: full tunneling forces traffic through corporate controls, not around them.</span><span class='qd'><b>Split tunneling forces all traffic through the firewall</b>: split tunneling deliberately lets some traffic go direct, bypassing the firewall.</span>" },
{ id:"D4-078", domain:4, obj:"4.3", diff:"medium", q:"Which protocol provides confidentiality and integrity for VoIP call signaling (as opposed to the media)?", options:["Plain SIP over UDP","SIP over TLS (SIPS)","SRTP","H.323 without security"], answer:1, explain:"<strong>SIP over TLS (SIPS)</strong> encrypts and authenticates the call-signaling channel, protecting call setup information from interception and tampering.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Plain SIP over UDP</b>: unencrypted SIP exposes signaling metadata and credentials.</span><span class='qd'><b>SRTP</b>: SRTP secures the media stream, not the signaling channel.</span><span class='qd'><b>H.323 without security</b>: unsecured H.323 provides no confidentiality for signaling.</span>" },
{ id:"D4-079", domain:4, obj:"4.3", diff:"easy", q:"Which technology provides end-to-end encryption and digital signatures for individual email messages using certificates?", options:["Telnet","NAT","S/MIME","STP"], answer:2, explain:"<strong>S/MIME</strong> uses X.509 certificates to encrypt and digitally sign individual email messages, providing confidentiality, integrity, and nonrepudiation end to end.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Telnet</b>: Telnet is an insecure remote-terminal protocol, not email security.</span><span class='qd'><b>NAT</b>: NAT translates addresses and does not secure email content.</span><span class='qd'><b>STP</b>: STP prevents Layer 2 loops and is unrelated to email.</span>" },
{ id:"D4-080", domain:4, obj:"4.3", diff:"medium", q:"An organization wants to reduce spoofed emails claiming to be from its domain and instruct receivers how to handle failures. Which combination BEST addresses email authentication?", options:["Only an SPF record","Only a stronger password policy","Disabling TLS on the mail server","SPF, DKIM, and DMARC"], answer:3, explain:"<strong>SPF, DKIM, and DMARC</strong> together authorize sending servers (SPF), cryptographically sign messages (DKIM), and publish alignment/handling policy with reporting (DMARC), sharply reducing spoofing.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Only an SPF record</b>: SPF alone can break on forwarding and lacks the policy/reporting DMARC adds.</span><span class='qd'><b>Only a stronger password policy</b>: passwords protect accounts but do not authenticate the sending domain.</span><span class='qd'><b>Disabling TLS on the mail server</b>: disabling TLS weakens transport security and does nothing against spoofing.</span>" },
{ id:"D4-081", domain:4, obj:"4.3", diff:"hard", q:"A CISO must secure third-party connectivity for a partner that needs limited access to one internal application. Which approach BEST enforces least privilege for the connection?", options:["Provide access only to the specific application via a brokered, segmented connection with strict ACLs","Grant the partner a full site-to-site VPN into the internal LAN","Share internal admin credentials with the partner","Open the application to the entire Internet"], answer:0, explain:"<strong>Provide access only to the specific application via a brokered, segmented connection with strict ACLs</strong> limits the partner to what is required, containing risk if the partner is compromised.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Grant the partner a full site-to-site VPN into the internal LAN</b>: full LAN access far exceeds least privilege and enables lateral movement.</span><span class='qd'><b>Share internal admin credentials with the partner</b>: sharing admin credentials destroys accountability and is grossly excessive.</span><span class='qd'><b>Open the application to the entire Internet</b>: exposing it publicly ignores the partner-only requirement and increases exposure.</span>" },
{ id:"D4-082", domain:4, obj:"4.3", diff:"medium", q:"Which control BEST protects a video-conferencing/collaboration platform from unauthorized attendees joining sensitive meetings?", options:["Publishing the meeting link publicly","Waiting rooms, unique meeting IDs, and enforced authentication/passcodes","Disabling all encryption","Reusing one static meeting ID for every meeting"], answer:1, explain:"<strong>Waiting rooms, unique meeting IDs, and enforced authentication/passcodes</strong> prevent uninvited attendees and 'meeting bombing' by controlling who can join sensitive sessions.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Publishing the meeting link publicly</b>: public links invite unauthorized attendees.</span><span class='qd'><b>Disabling all encryption</b>: disabling encryption exposes the session and does not control access.</span><span class='qd'><b>Reusing one static meeting ID for every meeting</b>: static IDs are easily guessed or shared, enabling intrusion.</span>" },
{ id:"D4-083", domain:4, obj:"4.3", diff:"hard", q:"A security team must choose a remote-access protocol for administrators. Which meets the requirement for encrypted, authenticated command-line access and is preferred over legacy alternatives?", options:["Telnet","rlogin","SSH","Bare RDP without NLA over the Internet"], answer:2, explain:"<strong>SSH</strong> provides strong encryption and authentication for remote command-line administration and is the preferred replacement for legacy cleartext protocols.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Telnet</b>: Telnet sends credentials and commands in cleartext.</span><span class='qd'><b>rlogin</b>: rlogin is a legacy, insecure remote-login protocol.</span><span class='qd'><b>Bare RDP without NLA over the Internet</b>: exposing RDP without Network Level Authentication on the Internet is a well-known high-risk misconfiguration.</span>" },
{ id:"D4-084", domain:4, obj:"4.3", diff:"medium", q:"Which statement BEST describes the security value of Multiprotocol Label Switching (MPLS) as a WAN transport for an enterprise?", options:["MPLS encrypts all customer traffic by default","MPLS makes VPNs unnecessary","MPLS authenticates end users","MPLS provides traffic separation and performance but does NOT provide encryption by itself"], answer:3, explain:"<strong>MPLS provides traffic separation and performance but does NOT provide encryption by itself</strong> is the key exam point: MPLS isolates VPN routing instances but customers must add encryption (e.g., IPsec) for confidentiality.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>MPLS encrypts all customer traffic by default</b>: MPLS does not encrypt payloads.</span><span class='qd'><b>MPLS makes VPNs unnecessary</b>: encryption VPNs are still needed for confidentiality over MPLS.</span><span class='qd'><b>MPLS authenticates end users</b>: MPLS is a transport labeling mechanism, not user authentication.</span>" },
{ id:"D4-085", domain:4, obj:"4.3", diff:"easy", q:"Which protocol is commonly used for secure remote graphical desktop access to Windows systems and should be protected with encryption and Network Level Authentication?", options:["RDP","SMTP","SNMP","ARP"], answer:0, explain:"<strong>RDP</strong> (Remote Desktop Protocol) provides remote graphical access to Windows systems and should be secured with TLS and Network Level Authentication and never exposed directly to the Internet.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>SMTP</b>: SMTP relays email, not remote desktops.</span><span class='qd'><b>SNMP</b>: SNMP manages devices and is not a desktop-access protocol.</span><span class='qd'><b>ARP</b>: ARP resolves IP to MAC at Layer 2.</span>" },
{ id:"D4-086", domain:4, obj:"4.3", diff:"medium", q:"An organization wants remote workers to reach internal resources without exposing those resources publicly, granting access per-application based on identity and device trust. Which modern model BEST fits?", options:["A public FTP server","Zero Trust Network Access (ZTNA)","Open RDP to each server","A flat VPN with full LAN access"], answer:1, explain:"<strong>Zero Trust Network Access (ZTNA)</strong> brokers per-application access based on verified identity and device posture, keeping internal resources hidden from the public Internet.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A public FTP server</b>: exposing files publicly is insecure and does not provide controlled internal access.</span><span class='qd'><b>Open RDP to each server</b>: exposing RDP invites brute-force and exploitation.</span><span class='qd'><b>A flat VPN with full LAN access</b>: full LAN access violates least privilege and enables lateral movement.</span>" },
{ id:"D4-087", domain:4, obj:"4.3", diff:"hard", q:"A partner integration requires exchanging data via an API over the Internet. Which combination BEST secures this third-party data communication?", options:["Plain HTTP with an API key in the URL","Emailing credentials in cleartext","Mutual TLS with strong authentication, least-privilege scopes, and encryption in transit","Allowing any source IP with no rate limiting"], answer:2, explain:"<strong>Mutual TLS with strong authentication, least-privilege scopes, and encryption in transit</strong> authenticates both endpoints, protects data on the wire, and limits what the partner can do, aligning with secure third-party connectivity.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Plain HTTP with an API key in the URL</b>: unencrypted HTTP exposes the key and data; keys in URLs get logged.</span><span class='qd'><b>Emailing credentials in cleartext</b>: cleartext credential distribution is easily intercepted.</span><span class='qd'><b>Allowing any source IP with no rate limiting</b>: open access with no throttling invites abuse and attack.</span>" },
{ id:"D4-088", domain:4, obj:"4.3", diff:"medium", q:"Which control BEST protects instant messaging and collaboration content from interception while stored and in transit within an enterprise platform?", options:["Broadcasting messages to all users","Disabling authentication","Storing messages in plaintext logs shared openly","End-to-end or transport encryption with access controls and DLP"], answer:3, explain:"<strong>End-to-end or transport encryption with access controls and DLP</strong> protects message confidentiality in transit and at rest while preventing sensitive-data leakage through the channel.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Broadcasting messages to all users</b>: broadcasting violates confidentiality entirely.</span><span class='qd'><b>Disabling authentication</b>: removing authentication exposes the platform to anyone.</span><span class='qd'><b>Storing messages in plaintext logs shared openly</b>: open plaintext logs leak sensitive content.</span>" },
{ id:"D4-089", domain:4, obj:"4.3", diff:"easy", q:"Which term describes a private, encrypted connection over a public network that lets a remote user securely access corporate resources?", options:["VPN","VLAN","NAT","DMZ"], answer:0, explain:"<strong>VPN</strong> (Virtual Private Network) creates an encrypted tunnel over a public network so remote users can reach corporate resources securely.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>VLAN</b>: a VLAN segments a LAN logically and does not tunnel over the public Internet.</span><span class='qd'><b>NAT</b>: NAT translates addresses and does not encrypt or tunnel securely.</span><span class='qd'><b>DMZ</b>: a DMZ is a segmented zone for public-facing servers, not a remote-access tunnel.</span>" },
{ id:"D4-090", domain:4, obj:"4.3", diff:"medium", q:"A remote-access solution must verify user identity with more than a password to counter credential theft. Which control is the BEST addition?", options:["A longer session timeout","Multifactor authentication (MFA)","Disabling account lockout","A shared team password"], answer:1, explain:"<strong>Multifactor authentication (MFA)</strong> requires an additional factor beyond the password, so stolen credentials alone cannot grant remote access.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A longer session timeout</b>: longer sessions increase exposure and do not verify identity.</span><span class='qd'><b>Disabling account lockout</b>: disabling lockout aids brute-force attacks.</span><span class='qd'><b>A shared team password</b>: shared passwords remove accountability and are easily leaked.</span>" },
{ id:"D4-091", domain:4, obj:"4.3", diff:"hard", q:"An enterprise phone system runs VoIP on the same VLAN as user PCs, and eavesdropping on calls is a concern. Which design change BEST reduces this risk?", options:["Broadcast all call audio to the LAN","Disable QoS entirely","Place voice on a separate voice VLAN and encrypt media with SRTP","Use a hub for the phones"], answer:2, explain:"<strong>Place voice on a separate voice VLAN and encrypt media with SRTP</strong> isolates voice traffic and encrypts the media stream, protecting confidentiality and quality.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Broadcast all call audio to the LAN</b>: broadcasting audio would expose calls, the opposite of the goal.</span><span class='qd'><b>Disable QoS entirely</b>: disabling QoS harms call quality and does not address eavesdropping.</span><span class='qd'><b>Use a hub for the phones</b>: a hub repeats traffic to all ports, making eavesdropping easier.</span>" },
{ id:"D4-092", domain:4, obj:"4.3", diff:"medium", q:"Which practice BEST addresses the risk that a third party's compromised network could pivot into your environment through an established connection?", options:["Granting the third party unrestricted VPN access","Skipping vendor security assessments","Sharing full network diagrams publicly","Continuous monitoring, network segmentation of the partner link, and contractual security requirements"], answer:3, explain:"<strong>Continuous monitoring, network segmentation of the partner link, and contractual security requirements</strong> contains and governs third-party access so a partner compromise cannot freely reach internal systems.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Granting the third party unrestricted VPN access</b>: unrestricted access maximizes pivot risk.</span><span class='qd'><b>Skipping vendor security assessments</b>: skipping assessments leaves partner risk unmanaged.</span><span class='qd'><b>Sharing full network diagrams publicly</b>: exposing architecture aids attackers.</span>" },
{ id:"D4-093", domain:4, obj:"4.3", diff:"easy", q:"Which email protocol lets a client retrieve and synchronize mail across multiple devices while leaving messages on the server?", options:["IMAP","SMTP","SNMP","NTP"], answer:0, explain:"<strong>IMAP</strong> synchronizes mail folders across devices while keeping messages on the server, and should be used over TLS for security.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>SMTP</b>: SMTP sends/relays mail; it is not a retrieval/sync protocol.</span><span class='qd'><b>SNMP</b>: SNMP manages network devices, not email.</span><span class='qd'><b>NTP</b>: NTP synchronizes time, not mailboxes.</span>" },
{ id:"D4-094", domain:4, obj:"4.3", diff:"hard", q:"An organization needs remote users' traffic to be inspected for malware and data loss even when working from home. Which architecture BEST meets this while scaling to a distributed workforce?", options:["Backhauling all traffic to a single legacy VPN concentrator","Secure Access Service Edge (SASE) integrating SWG, CASB, ZTNA, and FWaaS","No inspection to preserve privacy","A public open Wi-Fi policy"], answer:1, explain:"<strong>Secure Access Service Edge (SASE) integrating SWG, CASB, ZTNA, and FWaaS</strong> delivers cloud-based inspection and zero-trust access close to users, scaling security for a distributed workforce.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Backhauling all traffic to a single legacy VPN concentrator</b>: a single concentrator becomes a bottleneck and single point of failure.</span><span class='qd'><b>No inspection to preserve privacy</b>: skipping inspection leaves malware and data loss undetected.</span><span class='qd'><b>A public open Wi-Fi policy</b>: mandating open Wi-Fi increases exposure rather than securing remote work.</span>" },
{ id:"D4-095", domain:4, obj:"4.3", diff:"medium", q:"Which statement BEST captures why organizations enforce TLS on internal email retrieval protocols (IMAPS/POP3S) rather than plaintext IMAP/POP3?", options:["To make mailboxes larger","To speed up DNS resolution","To protect credentials and message contents from interception on the network","To reduce the number of VLANs"], answer:2, explain:"<strong>To protect credentials and message contents from interception on the network</strong> is the core reason: plaintext IMAP/POP3 exposes logins and mail to sniffing, which TLS prevents.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>To make mailboxes larger</b>: TLS has no effect on mailbox size.</span><span class='qd'><b>To speed up DNS resolution</b>: encryption of mail retrieval is unrelated to DNS speed.</span><span class='qd'><b>To reduce the number of VLANs</b>: TLS does not change network segmentation.</span>" },
{ id:"D4-096", domain:4, obj:"4.3", diff:"hard", q:"A company uses a cloud email service and wants to prevent business email compromise where attackers impersonate executives. Beyond SPF/DKIM/DMARC, which additional control MOST directly helps?", options:["Removing all spam filtering","Allowing external forwarding rules by default","Disabling logging of mail flow","User awareness training plus anti-impersonation/display-name analysis and MFA"], answer:3, explain:"<strong>User awareness training plus anti-impersonation/display-name analysis and MFA</strong> addresses the human and detection gaps in BEC that authentication records alone do not fully cover, including lookalike display names and account takeover.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Removing all spam filtering</b>: removing filtering increases malicious email reaching users.</span><span class='qd'><b>Allowing external forwarding rules by default</b>: auto-forwarding is a common BEC exfiltration tactic and should be restricted.</span><span class='qd'><b>Disabling logging of mail flow</b>: disabling logs removes the visibility needed to detect and investigate BEC.</span>" },
{ id:"D4-097", domain:4, obj:"4.3", diff:"medium", q:"Which control BEST secures data communications over an untrusted wireless hotspot for a traveling employee accessing corporate resources?", options:["Establishing an encrypted VPN tunnel before accessing corporate resources","Trusting the hotspot's captive portal","Using plaintext HTTP for speed","Disabling the device firewall"], answer:0, explain:"<strong>Establishing an encrypted VPN tunnel before accessing corporate resources</strong> protects data in transit over the untrusted hotspot, defeating local eavesdropping and on-path attacks.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Trusting the hotspot's captive portal</b>: a captive portal does not encrypt traffic or make the hotspot trustworthy.</span><span class='qd'><b>Using plaintext HTTP for speed</b>: plaintext exposes data to anyone on the hotspot.</span><span class='qd'><b>Disabling the device firewall</b>: disabling the firewall increases exposure on a hostile network.</span>" },
{ id:"D4-098", domain:4, obj:"4.3", diff:"easy", q:"Which term describes securely connecting two fixed office locations with an always-on encrypted tunnel between their gateways?", options:["Clientless portal","Site-to-site VPN","Guest Wi-Fi","Broadcast domain"], answer:1, explain:"<strong>Site-to-site VPN</strong> establishes a persistent encrypted tunnel between two site gateways so the offices communicate securely over the Internet.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Clientless portal</b>: a clientless portal is for individual user access, not gateway-to-gateway tunnels.</span><span class='qd'><b>Guest Wi-Fi</b>: guest Wi-Fi provides visitor access, not inter-office tunneling.</span><span class='qd'><b>Broadcast domain</b>: a broadcast domain is a Layer 2 concept, not a VPN.</span>" },
{ id:"D4-099", domain:4, obj:"4.3", diff:"medium", q:"An organization must decide how to authenticate a site-to-site VPN between its firewall and a partner's. Which method is generally MORE secure and scalable than a shared secret?", options:["A short shared pre-shared key reused everywhere","No authentication","Certificate-based (PKI) authentication","MAC filtering only"], answer:2, explain:"<strong>Certificate-based (PKI) authentication</strong> provides stronger, more scalable peer authentication than a static pre-shared key, avoiding secret reuse and supporting revocation.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A short shared pre-shared key reused everywhere</b>: reused, short PSKs are guessable and compromise all tunnels if leaked.</span><span class='qd'><b>No authentication</b>: without authentication, any peer could establish the tunnel.</span><span class='qd'><b>MAC filtering only</b>: MAC filtering is spoofable and inappropriate for VPN peer authentication.</span>" },
{ id:"D4-100", domain:4, obj:"4.3", diff:"hard", q:"A security architect must select the BEST approach to protect voice, video, and collaboration data as it traverses both the corporate WAN and the Internet to remote participants. Which comprehensive strategy is MOST appropriate?", options:["Rely solely on the WAN provider's promise of privacy","Send all media unencrypted to reduce latency","Use one shared meeting ID and no encryption","Encrypt signaling (SIP-TLS) and media (SRTP), segment collaboration traffic, and enforce authentication and access controls end to end"], answer:3, explain:"<strong>Encrypt signaling (SIP-TLS) and media (SRTP), segment collaboration traffic, and enforce authentication and access controls end to end</strong> protects confidentiality and integrity across all paths and participants, the comprehensive, defense-in-depth answer.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Rely solely on the WAN provider's promise of privacy</b>: provider assurances do not encrypt or authenticate your traffic end to end.</span><span class='qd'><b>Send all media unencrypted to reduce latency</b>: unencrypted media exposes sensitive conversations.</span><span class='qd'><b>Use one shared meeting ID and no encryption</b>: static IDs and no encryption invite intrusion and interception.</span>" }
);
